VALUES
  ('cpa-moex-01711', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，財產之買賣在下列何種情形，如無法提出支付價款之確實證明，將以贈與論， 依法課徵贈與稅？', '["伯父與侄兒之間", "夫妻之間", "姐妹之間", "朋友之間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01712', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，被繼承人如為經常居住中華民國境內之中華民國國民，但非為軍警公教人員因 執行職務死亡者，於98年1月23日以後死亡時，其免稅額為多少？', '["700萬元", "779萬元", "1,200萬元", "1,400萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01713', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '將作農業使用之農業用地及其地上農作物，贈與民法第1138條所定繼承人者，其土地及地上農作物價值 之全數不計入贈與總額。若受贈人自受贈之日起幾年內，未將該土地繼續作農業使用且未在有關機關所 令期限內恢復作農業使用，或雖在有關機關所令期限內已恢復作農業使用而再有未作農業使用情事者， 應追繳應納稅賦？', '["1年", "2年", "3年", "5年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01714', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '荔枝公司於X1年1月1日藉由契約協議取得對其供應商雪梨公司之控制，並使荔枝公司所需之技術 支援更為穩定、並減少存貨庫存，估計此項利益之公允價值為$80,000。荔枝公司並未持有雪梨公司 之任何股權。X1 年初雪梨公司股票之總市值為$320,000，可辨認淨資產之公允價值為$300,000。若 依可辨認淨資產比例衡量非控制權益，此無對價合併所產生之商譽為：', '["0", "$20,000", "$60,000", "$80,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01715', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '橘子公司於X6年4月1日以換發新股方式吸收合併蘋果公司，橘子公司為存續公司，換股比例為每 1股蘋果公司股票，換發橘子公司股票2股。X6年3月31日橘子公司及蘋果公司流通在外之普通股 分別為20,000股及40,000股。橘子公司X6年之淨利為$950,000，該公司X6年每股盈餘為何？', '["$8.53", "$10", "$11.25", "$12"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01716', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '秀岡公司於X5年1月1日取得青宇公司80%股權，當時青宇公司各項可辨認資產、負債之帳面金額 均等於公允價值，且無合併商譽。青宇公司於X6年1月1日增資發行新股5,000股，每股發行價格 $12，秀岡公司認購 1000 股外，均由其他個體購得。青宇公司增資前權益包括普通股股本（每股面 額$10）$450,000及保留盈餘$180,000。秀岡公司採權益法處理對青宇公司之投資，青宇公司增資發 行新股時，秀岡公司帳上應調整資本公積之金額為何？', '["增加$4,440", "減少$4,440", "增加$5,400", "減少$5,400"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01717', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1年1月1日大金公司以$68,000購入小山公司15%股權，當日小山公司權益為$500,000。大金公司 於X2年10月1日以$540,000另取得小山公司65%股權，並改採權益法處理對小山公司之投資，當 時小山公司各項可辨認資產、負債之帳面金額均與公允價值相等，原持有小山公司 15%股權之公允 價值為$112,000。小山公司X1年及X2年淨利分別為$72,000及$80,000，股利分別為$20,000及$30,000 （係於每年6月1日發放）。大金公司X2年底「投資小山公司」帳戶餘額及X2年投資收益（含股 利收入）分別為何？', '["$668,000及$16,000", "$608,000及$16,000", "$668,000及$20,500", "$608,000及$24,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01718', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '紐約公司於X1年1月1日與洋基公司簽訂技術合約，授權洋基公司使用紐約公司之某項技術，合約 期限為9年，不得展延。紐約公司於X5年1月1日以現金$500,000吸收合併洋基公司，當日洋基公 司可辨認淨資產之公允價值包括：與紐約公司所簽訂之技術合約$100,000、其他可辨認資產$740,000 及負債$320,000。該技術合約條件對紐約公司而言較市場條件不利，不利之金額為$80,000。合約規 定不得提前解約且紐約公司於收購日前並未針對此不利狀況認列任何資產或負債。紐約公司有關之 會計處理，下列敘述何者正確？', '["X5年1月1日應認列之技術合約結清損失$80,000", "X5年1月1日應認列「再取回之權利－技術合約」$80,000", "X5年1月1日應認列之合併商譽為$80,000", "X5年1月1日企業合併之移轉對價為$520,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01719', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '承上題，X6年1月1日紐約公司將收購日所取回之技術合約以$100,000售予尼克公司。當日紐約公 司應認列出售該技術合約之（損）益為何？', '["$80,000", "$60,000", "$20,000", "$10,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01720', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司持有乙公司90%股權，乙公司持有丙公司70%股權，聯屬公司間投資均以投資日股權淨值取 得。本年度各公司個別淨利如下：甲公司$120,000；乙公司$60,000；丙公司$30,000。試問合併淨利 與非控制權益淨利為何？', '["$180,900與$29,100", "$192,900與$17,100", "$195,000與$15,000", "$198,900與$11,100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
